@Composable
fun AlarmCard() {
    val ctx = LocalContext.current
    var alarms by remember { mutableStateOf(LockManager.getAlarms(ctx)) }
    var showAddDialog by remember { mutableStateOf(false) }

    Column(modifier = Modifier.fillMaxWidth()) {
        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
            Text("GUARDIAN SYSTEM ALARMS", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Black, letterSpacing = 2.sp)
            Text("ACTIVE UNITS: ${alarms.count { it.isEnabled }}", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
        }
        Spacer(Modifier.height(8.dp))

        alarms.forEach { alarm ->
            Surface(
                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
                color = if (alarm.isWakeMeUp && alarm.isEnabled) Color(0xFF271A1A) else Color(0xFF121212),
                shape = RoundedCornerShape(4.dp),
                border = BorderStroke(1.dp, if (alarm.isEnabled) (if(alarm.isWakeMeUp) Color(0xFFEF4444) else Color(0xFF6366F1)) else Color(0xFF222222))
            ) {
                Row(modifier = Modifier.padding(16.dp), verticalAlignment = Alignment.CenterVertically) {
                    Column(modifier = Modifier.weight(1f)) {
                        val displayHour = when { 
                            alarm.hour == 0 -> 12 
                            alarm.hour > 12 -> alarm.hour - 12 
                            else -> alarm.hour 
                        }
                        val amPm = if (alarm.hour < 12) "AM" else "PM"

                        Row(verticalAlignment = Alignment.Bottom) {
                            Text(String.format("%02d:%02d", displayHour, alarm.minute), 
                                color = if(alarm.isEnabled) Color.White else Color.DarkGray, 
                                fontSize = 32.sp, 
                                fontWeight = FontWeight.Black, 
                                fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                            Spacer(Modifier.width(4.dp))
                            Text(amPm, color = if(alarm.isEnabled) Color.Gray else Color.DarkGray, fontSize = 14.sp, fontWeight = FontWeight.Bold, modifier = Modifier.padding(bottom = 4.dp))
                        }
                        Text(alarm.label.uppercase(), color = if(alarm.isEnabled) Color.LightGray else Color.DarkGray, fontSize = 10.sp, fontWeight = FontWeight.Bold, letterSpacing = 1.sp)
                    }

                    Switch(checked = alarm.isEnabled, onCheckedChange = { updateAlarmState(ctx, alarm, it) { alarms = LockManager.getAlarms(ctx) } })

                    IconButton(onClick = { deleteAlarm(ctx, alarm) { alarms = LockManager.getAlarms(ctx) } }) {
                        Icon(Icons.Default.Close, null, tint = Color.DarkGray, modifier = Modifier.size(18.dp))
                    }
                }
            }
        }

        Button(
            onClick = { showAddDialog = true },
            modifier = Modifier.fillMaxWidth().height(48.dp).padding(top = 8.dp),
            shape = RoundedCornerShape(4.dp),
            colors = ButtonDefaults.buttonColors(containerColor = Color.DarkGray)
        ) {
            Icon(Icons.Default.Add, null, modifier = Modifier.size(16.dp))
            Spacer(Modifier.width(8.dp))
            Text("INITIALIZE NEW ALARM", fontSize = 11.sp, fontWeight = FontWeight.Black)
        }
    }
    if (showAddDialog) AlarmDialog(onDismiss = { showAddDialog = false }) { alarms = LockManager.getAlarms(ctx) }
}

