@Composable
fun AlarmDialog(onDismiss: () -> Unit, onUpdate: () -> Unit) {
    val ctx = LocalContext.current
    var hour by remember { mutableStateOf("07") }
    var minute by remember { mutableStateOf("00") }
    var isPm by remember { mutableStateOf(false) }
    var label by remember { mutableStateOf("ALARM") }
    var wakeMeUp by remember { mutableStateOf(true) }

    Dialog(onDismissRequest = onDismiss) {
        Surface(color = Color(0xFF121212), shape = RoundedCornerShape(8.dp), border = BorderStroke(1.dp, Color.Gray)) {
            Column(modifier = Modifier.padding(24.dp), horizontalAlignment = Alignment.CenterHorizontally) {
                Text("ALARM CONFIGURATION", color = Color.Gray, fontSize = 11.sp, fontWeight = FontWeight.Black, letterSpacing = 2.sp)
                Spacer(Modifier.height(24.dp))

                Row(verticalAlignment = Alignment.CenterVertically) {
                    TimeInputUnit(value = hour, onValueChange = { if(it.length <= 2) hour = it }, label = "HOUR")
                    Text(":", color = Color.White, fontSize = 48.sp, fontWeight = FontWeight.Black, modifier = Modifier.padding(horizontal = 12.dp))
                    TimeInputUnit(value = minute, onValueChange = { if(it.length <= 2) minute = it }, label = "MIN")

                    Spacer(Modifier.width(16.dp))

                    Column {
                        Text("AM", 
                            color = if (!isPm) Color.White else Color.DarkGray, 
                            fontSize = 18.sp, 
                            fontWeight = if (!isPm) FontWeight.Black else FontWeight.Normal,
                            modifier = Modifier.clickable { isPm = false })
                        Spacer(Modifier.height(8.dp))
                        Text("PM", 
                            color = if (isPm) Color.White else Color.DarkGray, 
                            fontSize = 18.sp, 
                            fontWeight = if (isPm) FontWeight.Black else FontWeight.Normal,
                            modifier = Modifier.clickable { isPm = true })
                    }
                }

                Spacer(Modifier.height(24.dp))
                OutlinedTextField(
                    value = label, 
                    onValueChange = { label = it }, 
                    modifier = Modifier.fillMaxWidth(), 
                    textStyle = androidx.compose.ui.text.TextStyle(fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace, color = Color.White),
                    placeholder = { Text("LABEL", color = Color.DarkGray) }
                )

                Spacer(Modifier.height(24.dp))

                Surface(
                    modifier = Modifier.fillMaxWidth(),
                    color = if(wakeMeUp) Color(0xFF450A0A) else Color(0xFF1A1A1A),
                    shape = RoundedCornerShape(4.dp),
                    border = BorderStroke(1.dp, if(wakeMeUp) Color.Red else Color.DarkGray)
                ) {
                    Row(modifier = Modifier.padding(12.dp), verticalAlignment = Alignment.CenterVertically) {
                        Switch(checked = wakeMeUp, onCheckedChange = { wakeMeUp = it }, colors = SwitchDefaults.colors(checkedThumbColor = Color.Red))
                        Spacer(Modifier.width(16.dp))
                        Column { 
                            Text("WAKE-ME-UP INTERLOCK", color = if(wakeMeUp) Color.White else Color.Gray, fontSize = 12.sp, fontWeight = FontWeight.Black)
                            Text("FORCED EXORCISM ON DISMISS", color = if(wakeMeUp) Color.Red else Color.DarkGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }

                Spacer(Modifier.height(32.dp))
                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(12.dp)) {
                    TextButton(onClick = onDismiss, modifier = Modifier.weight(1f)) {\ Text("ABORT", color = Color.Gray) }
                    Button(
                        onClick = {
                            var h = hour.toIntOrNull()?.coerceIn(1, 12) ?: 7
                            val m = minute.toIntOrNull()?.coerceIn(0, 59) ?: 0

                            // Convert to 24h format for internal storage
                            if (isPm && h < 12) h += 12
                            if (!isPm && h == 12) h = 0

                            val newAlarm = LockManager.GuardianAlarm(hour = h, minute = m, label = label, isWakeMeUp = wakeMeUp)

                            // Calculate Time Remaining for Toast
                            val now = java.util.Calendar.getInstance()
                            val target = java.util.Calendar.getInstance().apply {
                                set(java.util.Calendar.HOUR_OF_DAY, h)
                                set(java.util.Calendar.MINUTE, m)
                                set(java.util.Calendar.SECOND, 0)
                                if (before(now)) add(java.util.Calendar.DATE, 1)
                            }
                            val diffMs = target.timeInMillis - now.timeInMillis
                            val diffHours = diffMs / (1000 * 60 * 60)
                            val diffMins = (diffMs / (1000 * 60)) % 60

                            android.widget.Toast.makeText(ctx, "Alarm set for $diffHours hours and $diffMins minutes from now", android.widget.Toast.LENGTH_LONG).show()

                            val list = LockManager.getAlarms(ctx).toMutableList()
                            list.add(newAlarm)
                            LockManager.saveAlarms(ctx, list)
                            scheduleSystemAlarm(ctx, newAlarm)
                            onUpdate()
                            onDismiss()
                        }, 
                        modifier = Modifier.weight(1f), 
                        shape = RoundedCornerShape(4.dp),
                        colors = ButtonDefaults.buttonColors(containerColor = Color.White, contentColor = Color.Black)
                    ) { Text("ARM SYSTEM", fontWeight = FontWeight.Black) }
                }
            }
        }
    }
}

