                                fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                            Spacer(Modifier.width(8.dp))
                            Text(amPm, color = if(alarm.isEnabled) Color.Gray else Color.DarkGray, fontSize = 16.sp, fontWeight = FontWeight.Bold, modifier = Modifier.padding(bottom = 6.dp))
                        }

                        Row(verticalAlignment = Alignment.CenterVertically) {
                            if (alarm.isWakeMeUp) {
                                Icon(Icons.Default.Bolt, null, tint = Color.Red, modifier = Modifier.size(14.dp))
                                Spacer(Modifier.width(4.dp))
                            }
                            Text(alarm.label.uppercase(), color = if(alarm.isEnabled) Color.Gray else Color.DarkGray, fontSize = 11.sp, fontWeight = FontWeight.ExtraBold, letterSpacing = 1.sp)
                        }
                    }

                    Switch(
                        checked = alarm.isEnabled, 
                        onCheckedChange = { 
                            updateAlarmState(ctx, alarm, it) { 
                                alarms = LockManager.getAlarms(ctx) 
                            }
                        },
                        colors = SwitchDefaults.colors(
                            checkedThumbColor = if(alarm.isWakeMeUp) Color.Red else Color.White,
                            checkedTrackColor = if(alarm.isWakeMeUp) Color(0xFF450A0A) else Color(0xFF4338CA)
                        )
                    )
                }
            }
        }

        OutlinedButton(
            onClick = { showAddDialog = true },
            modifier = Modifier.fillMaxWidth().height(56.dp).padding(top = 12.dp),
            shape = RoundedCornerShape(12.dp),
            border = BorderStroke(1.dp, Color.DarkGray)
        ) {
            Icon(Icons.Default.Add, null, modifier = Modifier.size(20.dp), tint = Color.Gray)
            Spacer(Modifier.width(12.dp))
            Text("INITIALIZE NEW UNIT", fontSize = 12.sp, fontWeight = FontWeight.Black, color = Color.White)
        }
    }

    if (showAddDialog) {
        AlarmDialog(onDismiss = { showAddDialog = false }) { alarms = LockManager.getAlarms(ctx) }
    }

    if (editingAlarm != null) {
        AlarmDialog(
            existingAlarm = editingAlarm,
            onDismiss = { editingAlarm = null },
            onUpdate = { alarms = LockManager.getAlarms(ctx) }
        )
    }
}

