1014 |     private fun scheduleSystemAlarm(ctx: Context, alarm: LockManager.GuardianAlarm) {
1015 |         if (!alarm.isEnabled) return
1016 |         val am = ctx.getSystemService(Context.ALARM_SERVICE) as android.app.AlarmManager
1017 |         val intent = Intent(ctx, AlarmReceiver::class.java).apply {
1018 |             putExtra("WAKE_ME_UP", alarm.isWakeMeUp)
1019 |             putExtra("ALARM_ID", alarm.id)
1020 |         }
1021 |         // Hash the ID string to get a unique int request code
1022 |         val requestCode = alarm.id.hashCode()
1023 |         val pi = android.app.PendingIntent.getBroadcast(ctx, requestCode, intent, android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE)
1024 |         
1025 |         val calendar = java.util.Calendar.getInstance().apply {
1026 |             set(java.util.Calendar.HOUR_OF_DAY, alarm.hour)
1027 |             set(java.util.Calendar.MINUTE, alarm.minute)
1028 |             set(java.util.Calendar.SECOND, 0)
1029 |             if (before(java.util.Calendar.getInstance())) add(java.util.Calendar.DATE, 1)
1030 |         }
1031 | 
1032 |         if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.M) {
1033 |             am.setExactAndAllowWhileIdle(android.app.AlarmManager.RTC_WAKEUP, calendar.timeInMillis, pi)
1034 |         } else {
1035 |             am.setExact(android.app.AlarmManager.RTC_WAKEUP, calendar.timeInMillis, pi)
1036 |         }
1037 |     }
