1039 |     private fun cancelSystemAlarm(ctx: Context, alarmId: String) {
1040 |         val am = ctx.getSystemService(Context.ALARM_SERVICE) as android.app.AlarmManager
1041 |         val intent = Intent(ctx, AlarmReceiver::class.java)
1042 |         val pi = android.app.PendingIntent.getBroadcast(ctx, alarmId.hashCode(), intent, android.app.PendingIntent.FLAG_NO_CREATE or android.app.PendingIntent.FLAG_IMMUTABLE)
1043 |         if (pi != null) am.cancel(pi)
1044 |     }
