1046 |     private fun updateAlarmState(ctx: Context, alarm: LockManager.GuardianAlarm, enabled: Boolean, onUpdate: () -> Unit) {
1047 |         val list = LockManager.getAlarms(ctx).toMutableList()
1048 |         val index = list.indexOfFirst { it.id == alarm.id }
1049 |         if (index != -1) {
1050 |             val updated = list[index].copy(isEnabled = enabled)
1051 |             list[index] = updated
1052 |             LockManager.saveAlarms(ctx, list)
1053 |             if (enabled) scheduleSystemAlarm(ctx, updated) else cancelSystemAlarm(ctx, alarm.id)
1054 |             onUpdate()
1055 |         }
1056 |     }
