1325 |     private fun getMissingPermissions(ctx: Context): List<PermissionItem> {
1326 |         val list = mutableListOf<PermissionItem>()
1327 | 
1328 |         // 1. LOCATION FIRST (Prevents Accessibility Lockdown loop)
1329 |         if (ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.ACCESS_FINE_LOCATION) != android.content.pm.PackageManager.PERMISSION_GRANTED) {
1330 |             list.add(PermissionItem("Location (Fine)") { 
1331 |                 val i = Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS, Uri.parse("package:$packageName"))
1332 |                 it.startActivity(i)
1333 |                 android.widget.Toast.makeText(it, "Permissions -> Location -> Allow while using", android.widget.Toast.LENGTH_LONG).show()
1334 |             })
1335 |         } else if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.Q && 
1336 |                    ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.ACCESS_BACKGROUND_LOCATION) != android.content.pm.PackageManager.PERMISSION_GRANTED) {
1337 |             list.add(PermissionItem("Background Location") { 
1338 |                 val i = Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS)
1339 |                 i.data = Uri.parse("package:$packageName")
1340 |                 it.startActivity(i)
1341 |                 android.widget.Toast.makeText(it, "Set Location to 'Allow all the time'", android.widget.Toast.LENGTH_LONG).show()
1342 |             })
1343 |         }
1344 |         
1345 |         if (!Settings.canDrawOverlays(ctx)) {
1346 |             list.add(PermissionItem("Display Over Apps") { 
1347 |                 LockManager.startPermissionFixSession(it)
1348 |                 it.startActivity(Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION, Uri.parse("package:$packageName"))) 
1349 |             })
1350 |         }
1351 |         if (!(ctx.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager).isIgnoringBatteryOptimizations(ctx.packageName)) {
1352 |              list.add(PermissionItem("Ignore Battery Opt") { 
1353 |                  it.startActivity(Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS, Uri.parse("package:$packageName"))) 
1354 |              })
1355 |         }
1356 |         
1357 |         val expected = "$packageName/${GuardService::class.java.canonicalName}"
1358 |         val enabledServices = Settings.Secure.getString(ctx.contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES) ?: ""
1359 |         if (!enabledServices.contains(expected)) {
1360 |             list.add(PermissionItem("Accessibility") { it.startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)) })
1361 |         }
1362 |         
1363 |         if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.Q) {
1364 |             if (ctx.checkSelfPermission(android.Manifest.permission.ACTIVITY_RECOGNITION) != android.content.pm.PackageManager.PERMISSION_GRANTED) {
1365 |                 list.add(PermissionItem("Physical Activity") { 
1366 |                     (it as MainActivity).requestPermissions(arrayOf(android.Manifest.permission.ACTIVITY_RECOGNITION), 102)
1367 |                 })
1368 |             }
1369 |         }
1370 | 
1371 |         val nm = ctx.getSystemService(Context.NOTIFICATION_SERVICE) as android.app.NotificationManager
