                        val toggle = { isPm = !isPm }
                        Text("AM", 
                            color = if (!isPm) Color.White else Color.DarkGray, 
                            fontSize = 20.sp, 
                            fontWeight = if (!isPm) FontWeight.Black else FontWeight.Normal,
                            modifier = Modifier.clickable { isPm = false })
                        Spacer(Modifier.height(12.dp))
                        Text("PM", 
                            color = if (isPm) Color.White else Color.DarkGray, 
                            fontSize = 20.sp, 
                            fontWeight = if (isPm) FontWeight.Black else FontWeight.Normal,
                            modifier = Modifier.clickable { isPm = true })
                    }
                }

                Text(countdownText, color = Color(0xFF6366F1), fontSize = 11.sp, fontWeight = FontWeight.Bold, modifier = Modifier.padding(top = 16.dp))

                Spacer(Modifier.height(32.dp))

                OutlinedTextField(
                    value = label, 
                    onValueChange = { label = it }, 
                    modifier = Modifier.fillMaxWidth(),
                    label = { Text("DESIGNATION", fontSize = 10.sp) },
                    textStyle = androidx.compose.ui.text.TextStyle(fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace, color = Color.White),
                    colors = OutlinedTextFieldDefaults.colors(unfocusedBorderColor = Color(0xFF222222), focusedBorderColor = Color(0xFF6366F1))
                )

                Spacer(Modifier.height(20.dp))

                Surface(
                    modifier = Modifier.fillMaxWidth().clickable { wakeMeUp = !wakeMeUp },
                    color = if(wakeMeUp) Color(0xFF2A0505) else Color(0xFF111111),
                    shape = RoundedCornerShape(16.dp),
                    border = BorderStroke(1.dp, if(wakeMeUp) Color.Red else Color(0xFF222222))
                ) {
                    Row(modifier = Modifier.padding(16.dp), verticalAlignment = Alignment.CenterVertically) {
                        Icon(
                            imageVector = if(wakeMeUp) Icons.Default.Bolt else Icons.Default.Circle,
                            contentDescription = null,
                            tint = if(wakeMeUp) Color.Red else Color.Gray
                        )
                        Spacer(Modifier.width(16.dp))
                        Column { 
                            Text("WAKE-ME-UP PROTOCOL", color = if(wakeMeUp) Color.White else Color.Gray, fontSize = 12.sp, fontWeight = FontWeight.Black)
                            Text("FORCED DISPLACEMENT ON DISMISS", color = if(wakeMeUp) Color.Red.copy(alpha=0.7f) else Color.DarkGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }

                Spacer(Modifier.height(32.dp))

                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(12.dp)) {
                    if (existingAlarm != null) {
                        IconButton(
                            onClick = { deleteAlarm(ctx, existingAlarm) { onUpdate(); onDismiss() } },
                            modifier = Modifier.size(56.dp).background(Color(0xFF1A1A1A), RoundedCornerShape(12.dp))
                        ) {
                            Icon(Icons.Default.Delete, null, tint = Color.Red)
                        }
                    }

                    Button(
                        onClick = {
                            var h = hour.toIntOrNull()?.coerceIn(1, 12) ?: 7
                            val m = minute.toIntOrNull()?.coerceIn(0, 59) ?: 0
                            if (isPm && h < 12) h += 12
                            if (!isPm && h == 12) h = 0

                            val newAlarm = LockManager.GuardianAlarm(
                                id = existingAlarm?.id ?: java.util.UUID.randomUUID().toString(),
                                hour = h, 
                                minute = m, 
                                label = label, 
                                isWakeMeUp = wakeMeUp,
                                isEnabled = true
                            )

                            val list = LockManager.getAlarms(ctx).toMutableList()
                            list.removeIf { it.id == newAlarm.id }
                            list.add(newAlarm)
                            LockManager.saveAlarms(ctx, list)
                            scheduleSystemAlarm(ctx, newAlarm)

                            val vibrator = ctx.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
                            vibrator.vibrate(50)

                            onUpdate()
                            onDismiss()
                        }, 
                        modifier = Modifier.weight(1f).height(56.dp), 
                        shape = RoundedCornerShape(12.dp),
                        colors = ButtonDefaults.buttonColors(containerColor = Color.White, contentColor = Color.Black)
                    ) {
                        Text(if(existingAlarm == null) "ARM UNIT" else "UPDATE UNIT", fontWeight = FontWeight.Black)
                    }
                }
            }
        }
    }
