 892 |     @Composable
 893 |     fun AlarmDialog(existingAlarm: LockManager.GuardianAlarm? = null, onDismiss: () -> Unit, onUpdate: () -> Unit) {
 894 |         val ctx = LocalContext.current
 895 |         
 896 |         // Initial State Parsing
 897 |         val initial24h = existingAlarm?.hour ?: 7
 898 |         val initial12h = when {
 899 |             initial24h == 0 -> 12
 900 |             initial24h > 12 -> initial24h - 12
 901 |             else -> initial24h
 902 |         }
 903 |         val initialIsPm = initial24h >= 12
 904 | 
 905 |         var hour by remember { mutableStateOf(String.format("%02d", initial12h)) }
 906 |         var minute by remember { mutableStateOf(String.format("%02d", existingAlarm?.minute ?: 0)) }
