1067 |     private fun scheduleSystemAlarm(ctx: Context, alarm: LockManager.GuardianAlarm) {
1068 |         if (!alarm.isEnabled) return
1069 |         val am = ctx.getSystemService(Context.ALARM_SERVICE) as android.app.AlarmManager
1070 |         val intent = Intent(ctx, AlarmReceiver::class.java).apply {
1071 |             putExtra("WAKE_ME_UP", alarm.isWakeMeUp)
1072 |             putExtra("ALARM_ID", alarm.id)
1073 |         }
1074 |         // Hash the ID string to get a unique int request code
1075 |         val requestCode = alarm.id.hashCode()
1076 |         val pi = android.app.PendingIntent.getBroadcast(ctx, requestCode, intent, android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE)
1077 |         
1078 |         val calendar = java.util.Calendar.getInstance().apply {
1079 |             set(java.util.Calendar.HOUR_OF_DAY, alarm.hour)
1080 |             set(java.util.Calendar.MINUTE, alarm.minute)
1081 |             set(java.util.Calendar.SECOND, 0)
1082 |             if (before(java.util.Calendar.getInstance())) add(java.util.Calendar.DATE, 1)
1083 |         }
1084 | 
1085 |         if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.M) {
1086 |             am.setExactAndAllowWhileIdle(android.app.AlarmManager.RTC_WAKEUP, calendar.timeInMillis, pi)
1087 |         } else {
1088 |             am.setExact(android.app.AlarmManager.RTC_WAKEUP, calendar.timeInMillis, pi)
1089 |         }
1090 |     }
1091 | 
1092 |     private fun cancelSystemAlarm(ctx: Context, alarmId: String) {
1093 |         val am = ctx.getSystemService(Context.ALARM_SERVICE) as android.app.AlarmManager
1094 |         val intent = Intent(ctx, AlarmReceiver::class.java)
1095 |         val pi = android.app.PendingIntent.getBroadcast(ctx, alarmId.hashCode(), intent, android.app.PendingIntent.FLAG_NO_CREATE or android.app.PendingIntent.FLAG_IMMUTABLE)
1096 |         if (pi != null) am.cancel(pi)
1097 |     }
