1099 |     private fun updateAlarmState(ctx: Context, alarm: LockManager.GuardianAlarm, enabled: Boolean, onUpdate: () -> Unit) {
1100 |         val list = LockManager.getAlarms(ctx).toMutableList()
1101 |         val index = list.indexOfFirst { it.id == alarm.id }
1102 |         if (index != -1) {
1103 |             val updated = list[index].copy(isEnabled = enabled)
1104 |             list[index] = updated
1105 |             LockManager.saveAlarms(ctx, list)
1106 |             if (enabled) scheduleSystemAlarm(ctx, updated) else cancelSystemAlarm(ctx, alarm.id)
1107 |             onUpdate()
1108 |         }
1109 |     }
